  tipo: $('WH-Analise').item.json.body.data.tipo || 'PROVAS',
  arquivos: $('WH-Analise').item.json.body.data.arquivos || [],
  contexto: $('WH-Analise').item.json.body.data.contexto || '',
  status: 'PROCESSANDO',
