// C1 — Preparar array de documentos para extração
const ctx = $('B3-Process').item.json;
const arquivos = ctx.arquivos_input || [];

const docs = arquivos.map(arq => ({
  filename: arq.file_name || arq.filename || 'documento.pdf',
  storage_path: arq.path || arq.storage_path || '',
  mime_type: arq.mime_type || 'application/pdf',
  documento_tipo: null,
  extraction_model: null,
  extracted: null,
  qualidade_extracao: 0
}));

// Sempre retornar ao menos 1 item com o contexto
// _has_docs indica se tem arquivos para processar
if (docs.length === 0) {
  return [{ json: { ...ctx, docs_extraidos: [], total_docs: 0, qualidade_media: 0, _has_docs: false } }];
}
return docs.map(d => ({ json: { ...ctx, doc_atual: d, _has_docs: true } }));

// C5 — Formatar texto extraído do PDF
const ctx = $('C2-Loop-Docs').item.json;
const extracted = $input.item;

const texto = extracted.json?.text || '';
const DOC_BUDGET = 20000; // chars por doc
const texto_truncado = texto.substring(0, DOC_BUDGET);
const qualidade = texto_truncado.trim().length > 100 ? 80 : 20;

return [{
  json: {
    ...ctx,
    doc_atual: {
      ...ctx.doc_atual,
      extracted: {
        texto_completo: texto_truncado,
        qualidade_extracao: qualidade,
        method: 'pdf_native'
      },
      extraction_model: 'n8n-extract-pdf',
      qualidade_extracao: qualidade
    }
  }
}];

// D1 — Consolidar todos os docs extraídos e preparar para análise
const allDocs = $input.all().map(item => item.json.doc_atual);
const ctx = $input.first().json;

// Consolidar docs
const docs_extraidos = allDocs.filter(d => d && d.extracted);
const qualidade_media = docs_extraidos.length > 0
  ? Math.round(docs_extraidos.reduce((s, d) => s + (d.qualidade_extracao || 0), 0) / docs_extraidos.length)
  : 0;

return [{
  json: {
    ...ctx,
    docs_extraidos,
    total_docs: docs_extraidos.length,
    qualidade_media
  }
}];

// D5 — Montar pacote completo para análise
const ctx = $('D2-PassCtx').item.json;
const ragRaw = $input.item.json._rag_results || [];

const ragResults = Array.isArray(ragRaw) ? ragRaw : [];
const jurisprudencias = ragResults.map(c => ({
  titulo: c.titulo,
  conteudo: c.conteudo?.substring(0, 500),
  score: c.score,
  source_type: c.source_type,
  tribunal: c.metadata?.tribunal || null
}));

// Truncar blocos para context window (max 200 chars cada)
const blocos_truncados = (ctx.blocos || []).map(b => ({
  id: b.id,
  titulo: b.titulo,
  tag_ids: b.tag_ids,
  conteudo_preview: (b.conteudo_preview || '').substring(0, 200)
}));

return [{
  json: {
    analise_id: ctx.analise_id,
    organizacao_id: ctx.organizacao_id,
    processo_id: ctx.processo_id,
    request_id: ctx.request_id,
    user_id: ctx.user_id,
    tipo_analise: ctx.tipo_analise,
    processo: ctx.processo,
    empresa: ctx.empresa,
    categoria_id: ctx.categoria_id,
    categoria_nome: ctx.categoria_nome,
    cliente: ctx.cliente,
    advogado: ctx.advogado,
    comarca: ctx.comarca,
    docs_extraidos: ctx.docs_extraidos,
    total_docs: ctx.total_docs,
    qualidade_media: ctx.qualidade_media,
    tags: ctx.tags || [],
    total_tags: ctx.total_tags || 0,
    blocos: blocos_truncados,
    total_blocos: ctx.total_blocos || 0,
    playbook: ctx.playbook,
    jurisprudencias: {
      total: jurisprudencias.length,
      chunks: jurisprudencias
    },
    analise_anterior: ctx.analise_anterior,
    modelo_template: ctx.modelo_template || null,
    ia_resumo_existente: ctx.ia_resumo_existente || null,
    chance_sucesso_existente: ctx.chance_sucesso_existente || null
  }
}];

// E2 — Preparar input para Claude Sonnet (análise unificada + peticao_base + relatorio)
const p = $('D5-MontarPacote').item.json;

const SYSTEM_PROMPT = `<identidade>
Você é a OlivIA, analista probatória sênior do escritório Midas (MDX LegalTech).
Especializada em direito do consumidor, restrições de crédito e análise documental probatória.
</identidade>

<objetivo>
Realizar análise probatória COMPLETA. Você deve:
1. Analisar as provas documentais do processo
2. Para cada TAG da categoria, decidir qual BLOCO DE TEXTO usar (ou gerar pergunta se incerto)
3. Gerar uma PETIÇÃO BASE estruturada por blocos seguindo o template do modelo (quando fornecido)
4. Gerar um RELATÓRIO EXECUTIVO completo do processo para o advogado
5. Retornar SEMPRE um JSON válido e estruturado — NENHUM texto fora do JSON

REGRA ABSOLUTA: Sua resposta é EXCLUSIVAMENTE um objeto JSON. Nenhum texto antes ou depois.
</objetivo>

<regra_jurisprudencia_absoluta>
REGRA ABSOLUTA: Você SOMENTE pode citar jurisprudências presentes em <jurisprudencia_rag>.
NÃO invente, NÃO cite STJ/STF/TJRS ou qualquer tribunal que não esteja no banco fornecido.
Se não há jurisprudência relevante no banco, NÃO cite nenhuma — omita a seção de jurisprudência.
</regra_jurisprudencia_absoluta>

<legislacao_base>
- CDC Art. 43: Cadastros de inadimplentes — prazo máximo 5 anos, comunicação prévia obrigatória
- CDC Art. 14: Responsabilidade objetiva do fornecedor
- CDC Art. 6, VIII: Inversão do ônus da prova
- CDC Art. 42: Vedação de exposição ao ridículo na cobrança
- CC Art. 186 e 927: Responsabilidade civil por ato ilícito
- Súmula 385 STJ: Negativação preexistente legítima afasta dano moral
- Súmula 479 STJ: Responsabilidade objetiva de instituições financeiras
- Súmula 359 STJ: Comunicação prévia ao consumidor obrigatória
- Dano moral in re ipsa em negativação indevida
</legislacao_base>

<playbook_categoria>
${p.playbook?.instrucoes || 'Análise padrão — sem playbook específico para esta categoria.'}
</playbook_categoria>`;

// Documentos extraídos
const TOTAL_DOC_BUDGET = 80000;
let usedChars = 0;
const docsTexto = (p.docs_extraidos || []).map((d, i) => {
  if (usedChars >= TOTAL_DOC_BUDGET) return null;
  const textoRaw = d.extracted?.texto_completo?.substring(0, 15000) || '(sem texto extraído)';
  const texto = textoRaw.substring(0, TOTAL_DOC_BUDGET - usedChars);
  usedChars += texto.length;
  return `[DOC ${i+1}: ${d.filename}]\n${texto}`;
}).filter(Boolean).join('\n\n---\n\n');

const tagsTexto = (p.tags || []).map(t =>
  `Tag ID: ${t.id} | Código: ${t.codigo} | Nome: ${t.nome}`
).join('\n');

const blocosTexto = (p.blocos || []).map(b =>
  `Bloco ID: ${b.id} | Titulo: ${b.titulo}\nPreview: ${b.conteudo_preview}`
).join('\n---\n');

const jurisTexto = (p.jurisprudencias?.chunks || []).map((j, i) =>
  `[JURIS ${i+1}] ${j.titulo} (score: ${j.score?.toFixed(2)})\n${j.conteudo}`
).join('\n\n');

const anteriorTexto = p.analise_anterior
  ? `ANÁLISE ANTERIOR (${p.analise_anterior.created_at?.substring(0,10)}): ${JSON.stringify(p.analise_anterior.resultado?.visao_geral || '').substring(0, 500)}`
  : 'Primeira análise deste processo.';

const resumoIATexto = p.ia_resumo_existente
  ? `\n\n<resumo_processo_ia>\n${p.ia_resumo_existente}\n</resumo_processo_ia>`
  : '';

const templateBaseTexto = p.modelo_template?.conteudo_template
  ? `\n\n<template_base_peticao nome="${p.modelo_template.nome || ''}">
Este é o esqueleto do modelo de petição do advogado. Use como estrutura base OBRIGATÓRIA.
Siga EXATAMENTE a estrutura de seções/tags. Pode criar novas tags entre as existentes.
${p.modelo_template.conteudo_template}
</template_base_peticao>`
  : '';

const USER_MESSAGE = `<processo>
Número: ${p.processo?.numero_cnj || p.processo?.numero_processo || 'N/A'}
Tipo: ${p.processo?.tipo_processo || 'N/A'}
Objeto: ${p.processo?.objeto || 'N/A'}
Empresa Ré: ${p.empresa?.nome || 'N/A'}
Categoria: ${p.categoria_nome}
Cliente: ${p.cliente?.nome || 'N/A'}
Polo: ${p.processo?.polo_representado || 'autor'}
Valor da Causa: ${p.processo?.valor_causa ? 'R$ ' + p.processo.valor_causa : 'N/A'}
</processo>
${resumoIATexto}

<documentos_extraidos>
${docsTexto || '(Nenhum documento enviado)'}
</documentos_extraidos>

<tags_da_categoria title="Tags = perguntas que a IA deve responder com blocos">
${tagsTexto || '(Nenhuma tag cadastrada para esta categoria)'}
</tags_da_categoria>

<blocos_disponiveis title="Blocos = opções de resposta para as tags">
${blocosTexto || '(Nenhum bloco cadastrado)'}
</blocos_disponiveis>

<jurisprudencia_rag>
${jurisTexto || '(Sem jurisprudência encontrada no banco — NÃO cite nenhuma)'}
</jurisprudencia_rag>

<contexto_historico>
${anteriorTexto}
</contexto_historico>

<contexto_adicional>
${p.contexto_adicional || ''}
</contexto_adicional>
${templateBaseTexto}

<instrucoes_resposta>
Retorne um JSON com EXATAMENTE esta estrutura (sem campos extras no nível raiz, sem markdown):
{
  "visao_geral": "resumo executivo do caso",
  "pontos_fortes": ["string"],
  "pontos_fracos": ["string"],
  "analise_probatoria": "análise detalhada das provas",
  "riscos": [{"descricao": "string", "severidade": "ALTO|MEDIO|BAIXO", "mitigacao": "string"}],
  "recomendacoes": ["string"],
  "chance_sucesso": 1 ou 2 ou 3,
  "documentos_faltantes": ["string"],
  "analise_tags": [
    {
      "tag_id": "uuid",
      "tag_nome": "string",
      "bloco_id": "uuid ou null",
      "bloco_titulo": "string ou null",
      "confianca": 0.0-1.0,
      "justificativa": "por que escolheu este bloco",
      "pergunta_usuario": "null ou string (quando confianca < 0.7)"
    }
  ],
  "perguntas_triagem": [
    {
      "id": "string único",
      "ordem": 1,
      "texto": "pergunta para o usuário",
      "tipo": "text|textarea|select|multiselect|date|number",
      "obrigatoria": true,
      "opcoes": [],
      "tag_ref": "uuid ou null",
      "contexto": "por que estamos perguntando"
    }
  ],
  "peticao_base": {
    "blocos_resolvidos": [
      {
        "tag_id": "uuid da tag ou null se tag nova",
        "tag_nome": "nome da tag/seção",
        "posicao": 1,
        "bloco_id": "uuid do bloco do banco ou null se gerado",
        "titulo_secao": "título da seção na petição",
        "conteudo_html": "<h2>Título</h2><p>Conteúdo em HTML com <strong>negrito</strong></p>",
        "tag_nova": false,
        "confianca": 0.92,
        "justificativa": "por que este bloco aqui"
      }
    ],
    "tags_novas_criadas": [
      {
        "tag_nome": "nome da nova tag",
        "posicao_entre": ["tag_id_anterior_ou_null", "tag_id_posterior_ou_null"],
        "conteudo_html": "<p>Conteúdo HTML da seção nova</p>",
        "justificativa": "por que criou esta seção extra"
      }
    ],
    "total_blocos": 0,
    "blocos_do_banco": 0,
    "blocos_gerados": 0
  },
  "relatorio_processo": {
    "visao_geral_executiva": "resumo executivo em 2-3 frases para o advogado",
    "pontos_fortes": ["argumento forte com base nas provas"],
    "pontos_fracos": ["vulnerabilidade a ser mitigada"],
    "analise_probatoria_detalhada": "análise técnica completa",
    "riscos_processuais": [{"descricao": "string", "severidade": "ALTO|MEDIO|BAIXO", "mitigacao": "string"}],
    "recomendacoes_estrategicas": ["ação recomendada"],
    "documentos_faltantes": ["documento que fortaleceria o caso"],
    "jurisprudencias_aplicadas": ["apenas juris do banco fornecido"],
    "chance_sucesso": 1,
    "chance_sucesso_justificativa": "por que esta chance"
  },
  "categoria_analisada": "${p.categoria_nome}",
  "playbook_aplicado": "${p.playbook?.nome || 'Genérico'}",
  "tags_analisadas": ${(p.tags || []).length},
  "tags_resolvidas": 0,
  "tags_pendentes": 0
}

REGRAS para peticao_base:
- Seguir template_base como esqueleto OBRIGATÓRIO quando fornecido
- Tags com confianca >= 0.7: gerar conteudo_html completo com o bloco escolhido
- Tags com confianca < 0.7: conteudo_html = "<p>{{NOME_DA_TAG}}</p>" (placeholder)
- HTML deve usar <h2> para títulos, <p> para parágrafos, <strong> para negrito jurídico
- Jurisprudência SOMENTE do banco fornecido em jurisprudencia_rag
- conteudo_html deve ser auto-suficiente (sem referências a outros blocos)

Threshold de confiança: >= 0.7 → usa o bloco. < 0.7 → preenche pergunta_usuario e bloco_id = null.
</instrucoes_resposta>`;

return [{
  json: {
    ...p,
    system_prompt: SYSTEM_PROMPT,
    user_message: USER_MESSAGE
  }
}];

// E4 — Parse resultado do Claude + validação (v2 com peticao_base + relatorio)
const refs = $('E2-PrepararInput-Claude').first().json;
const output = $input.item.json;

// Extrair texto (LangChain Anthropic node)
let raw = '';
if (typeof output.text === 'string') {
  raw = output.text;
} else if (output.content && Array.isArray(output.content)) {
  const textBlock = output.content.find(b => b.type === 'text');
  raw = textBlock ? textBlock.text : '';
}

// Capturar tokens e custo (claude-sonnet-4-6: $3/$15 /M tokens)
const usage = output.usage || output.response_metadata?.usage || {};
const inputTokens = usage.input_tokens || 0;
const outputTokens = usage.output_tokens || 0;
const totalTokens = inputTokens + outputTokens;
const custoUsd = Number(((inputTokens * 3 + outputTokens * 15) / 1000000).toFixed(6));

// Parse JSON
let resultado = null;
let parseOk = false;

try {
  let clean = raw.trim();
  clean = clean.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  const jsonStart = clean.indexOf('{');
  if (jsonStart > 0) clean = clean.substring(jsonStart);
  resultado = JSON.parse(clean);
  parseOk = true;

  // Normalizar campos array obrigatórios
  const camposArray = ['pontos_fortes', 'pontos_fracos', 'riscos', 'recomendacoes', 'documentos_faltantes', 'analise_tags', 'perguntas_triagem'];
  for (const field of camposArray) {
    if (!Array.isArray(resultado[field])) resultado[field] = [];
  }
  if (!resultado.visao_geral) resultado.visao_geral = 'Análise concluída.';
  const cs = parseInt(resultado.chance_sucesso);
  resultado.chance_sucesso = (cs >= 1 && cs <= 3) ? cs : 2;

  // Calcular tags_resolvidas e pendentes
  const analise_tags = resultado.analise_tags || [];
  resultado.tags_resolvidas = analise_tags.filter(t => t.confianca >= 0.7 && t.bloco_id).length;
  resultado.tags_pendentes = analise_tags.filter(t => t.confianca < 0.7 || !t.bloco_id).length;

  // Normalizar peticao_base
  if (!resultado.peticao_base || typeof resultado.peticao_base !== 'object') {
    resultado.peticao_base = { blocos_resolvidos: [], tags_novas_criadas: [], total_blocos: 0, blocos_do_banco: 0, blocos_gerados: 0 };
  }
  if (!Array.isArray(resultado.peticao_base.blocos_resolvidos)) resultado.peticao_base.blocos_resolvidos = [];
  if (!Array.isArray(resultado.peticao_base.tags_novas_criadas)) resultado.peticao_base.tags_novas_criadas = [];

  // Normalizar relatorio_processo
  if (!resultado.relatorio_processo || typeof resultado.relatorio_processo !== 'object') {
    resultado.relatorio_processo = {
      visao_geral_executiva: resultado.visao_geral || '',
      pontos_fortes: resultado.pontos_fortes || [],
      pontos_fracos: resultado.pontos_fracos || [],
      analise_probatoria_detalhada: resultado.analise_probatoria || '',
      riscos_processuais: resultado.riscos || [],
      recomendacoes_estrategicas: resultado.recomendacoes || [],
      documentos_faltantes: resultado.documentos_faltantes || [],
      jurisprudencias_aplicadas: [],
      chance_sucesso: resultado.chance_sucesso || 2,
      chance_sucesso_justificativa: ''
    };
  }
  const rp = resultado.relatorio_processo;
  if (!Array.isArray(rp.pontos_fortes)) rp.pontos_fortes = [];
  if (!Array.isArray(rp.pontos_fracos)) rp.pontos_fracos = [];
  if (!Array.isArray(rp.riscos_processuais)) rp.riscos_processuais = [];
  if (!Array.isArray(rp.recomendacoes_estrategicas)) rp.recomendacoes_estrategicas = [];
  if (!Array.isArray(rp.documentos_faltantes)) rp.documentos_faltantes = [];
  if (!Array.isArray(rp.jurisprudencias_aplicadas)) rp.jurisprudencias_aplicadas = [];

} catch (e) {
  resultado = {
    visao_geral: 'Análise concluída mas parsing falhou: ' + e.message,
    pontos_fortes: [], pontos_fracos: [], analise_probatoria: raw.substring(0, 1000),
    riscos: [], recomendacoes: [], chance_sucesso: 2, documentos_faltantes: [],
    analise_tags: [], perguntas_triagem: [], tags_resolvidas: 0, tags_pendentes: 0,
    categoria_analisada: refs.categoria_nome || '',
    peticao_base: { blocos_resolvidos: [], tags_novas_criadas: [], total_blocos: 0, blocos_do_banco: 0, blocos_gerados: 0 },
    relatorio_processo: {
      visao_geral_executiva: 'Parsing do resultado falhou: ' + e.message,
      pontos_fortes: [], pontos_fracos: [], analise_probatoria_detalhada: '',
      riscos_processuais: [], recomendacoes_estrategicas: [], documentos_faltantes: [],
      jurisprudencias_aplicadas: [], chance_sucesso: 2, chance_sucesso_justificativa: ''
    }
  };
  parseOk = false;
}

return [{
  json: {
    analise_id: refs.analise_id,
    organizacao_id: refs.organizacao_id,
    processo_id: refs.processo_id,
    resultado,
    peticao_base: resultado.peticao_base,
    relatorio_processo: resultado.relatorio_processo,
    tags_resolvidas: resultado.tags_resolvidas,
    tags_pendentes: resultado.tags_pendentes,
    perguntas_triagem: resultado.perguntas_triagem,
    meta: {
      parse_ok: parseOk,
      tokens_usados: totalTokens,
      custo_usd: custoUsd,
      modelo_usado: 'claude-sonnet-4-6'
    }
  }
}];

