// B1-PROCESS — Montar objeto completo do processo + buscar template do modelo
const https = require('https');
const SUPA_HOST = 'qdivfairxhdihaqqypgb.supabase.co';
const SUPA_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFkaXZmYWlyeGhkaWhhcXF5cGdiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTA3MzcwOCwiZXhwIjoyMDg2NjQ5NzA4fQ.zu_reCiKzCqLETOWxytYQmez1SIwFRDlOruzsLOpBeY';

function supaGet(path) {
  return new Promise((resolve, reject) => {
    const req = https.request({ hostname: SUPA_HOST, path, method: 'GET',
      headers: { 'apikey': SUPA_KEY, 'Authorization': 'Bearer ' + SUPA_KEY, 'Content-Type': 'application/json' }
    }, (res) => {
      let data = '';
      res.on('data', c => { data += c; });
      res.on('end', () => {
        if (res.statusCode >= 400) return reject(new Error('SUPA ' + res.statusCode + ': ' + data.substring(0, 300)));
        try { resolve(data ? JSON.parse(data) : null); } catch(e) { resolve(data); }
      });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('timeout')); });
    req.end();
  });
}

const ctx = $('B1-Prep').item.json;
const processosRaw = $('B1-HTTP-Processo').item.json;
const analisesResp = $('B1-HTTP-AnaliseAnt').item.json;
