const empresa = processo.empresa || {};
const categoria = empresa.categoria || {};
const analises = Array.isArray(analisesRaw) ? analisesRaw : [];
const analise_anterior = analises[0] || null;

// Buscar template do modelo se modelo_grupo_id foi fornecido
let modelo_template = null;
if (ctx.modelo_grupo_id) {
  try {
    const grupos = await supaGet('/rest/v1/olivia_modelos_grupo?id=eq.' + ctx.modelo_grupo_id + '&select=id,nome,active_version_id');
    const grupo = Array.isArray(grupos) && grupos[0] ? grupos[0] : null;
    if (grupo && grupo.active_version_id) {
      const versoes = await supaGet('/rest/v1/olivia_modelos_peticao?id=eq.' + grupo.active_version_id + '&select=id,nome,conteudo_template');
      const versao = Array.isArray(versoes) && versoes[0] ? versoes[0] : null;
      if (versao && versao.conteudo_template) {
        modelo_template = { id: versao.id, nome: versao.nome, conteudo_template: versao.conteudo_template };
      }
    }
  } catch(e) {
    // Silently fail — análise continua sem template
  }
}

return [{
  json: {
    analise_id: ctx.analise_id,
    organizacao_id: ctx.organizacao_id,
    request_id: ctx.request_id,
    user_id: ctx.user_id,
    processo_id: ctx.processo_id,
